const API_BASE = "http://localhost:5000/api/v1";
async function uploadDocument(files) {
    const formData = new FormData();
    // Separate document file and metadata.json
    let mainFile = null;
    let metadataFile = null;
    for (const file of files){
        if (file.name === 'metadata.json') {
            metadataFile = file;
        } else if (file.name.endsWith('.pptx') || file.name.endsWith('.pdf') || file.name.endsWith('.docx')) {
            mainFile = file;
        }
    }
    if (!mainFile) {
        throw new Error("No document file found. Please upload a .pptx, .pdf, or .docx file");
    }
    formData.append("file", mainFile);
    if (metadataFile) {
        formData.append("metadata_file", metadataFile);
    }
    const response = await fetch(`${API_BASE}/upload`, {
        method: "POST",
        body: formData
    });
    if (!response.ok) {
        throw new Error("Upload failed");
    }
    return response.json();
}
async function validateDocument(documentId, options) {
    const response = await fetch(`${API_BASE}/validate/${documentId}`, {
        method: "POST",
        headers: {
            "Content-Type": "application/json"
        },
        body: JSON.stringify(options || {})
    });
    if (!response.ok) {
        throw new Error("Validation failed");
    }
}
async function getValidationStatus(documentId) {
    const response = await fetch(`${API_BASE}/status/${documentId}`);
    if (!response.ok) {
        throw new Error("Failed to fetch status");
    }
    return response.json();
}
async function getValidationResults(documentId) {
    const response = await fetch(`${API_BASE}/results/${documentId}`);
    if (!response.ok) {
        throw new Error("Failed to fetch results");
    }
    return response.json();
}
async function applyFixes(documentId) {
    const response = await fetch(`${API_BASE}/fix/${documentId}`, {
        method: "POST"
    });
    if (!response.ok) {
        throw new Error("Failed to apply fixes");
    }
}
async function downloadCorrectedDocument(documentId) {
    const response = await fetch(`${API_BASE}/download/${documentId}?type=corrected`);
    if (!response.ok) {
        throw new Error("Failed to download document");
    }
    return response.blob();
}
async function listDocuments() {
    const response = await fetch(`${API_BASE}/list`);
    if (!response.ok) {
        throw new Error("Failed to list documents");
    }
    const data = await response.json();
    // Backend returns { total, limit, offset, documents }
    return data.documents || [];
}
async function deleteDocument(documentId) {
    const response = await fetch(`${API_BASE}/delete/${documentId}`, {
        method: "DELETE"
    });
    if (!response.ok) {
        throw new Error("Failed to delete document");
    }
}
